custom_css:
/*
* 主题名称：Book Extract - 《都柏林人》&《大雪将至》日间冰蓝毛玻璃版 (双层错落慢雪·暴雪增量纯净版)
* 视觉风格：极简出版物、西式水印、阶梯式诗歌排版、原生毛玻璃透传、微凸浮雕排版、不规则摇摆满屏大雪
* 框架编写/整理：墨千尾（discord@这对吗/inkfoxxxx） | 二创重构：vessel
* 核心逻辑：天地分离交互；Char/User双轨分离；思维链截断；日间色彩光影反转；双层非同频摇摆风雪超载引擎；隐匿机械控件。
* 借鉴声明：
*   1. 基础框架借用自：墨千尾
*   2. 提示词防隐形补丁借用自：blue
*   3. 编辑与更多按钮替换代码借用自：@qiyigeming
*   4. 宽屏正文代码借用自：@inkfoxxxx
*   5. 顶栏全版本兼容类名借用自：@gloriamukuhiba
*   6. 第三层摇摆雪花动画动效逻辑由：Vessel提供并指导粒子增量调优
*/

/* === 先导篇：字体导入 === */
/* 1. 正文与主UI字体：寒宋体 */
@import url("https://fontsapi.zeoseven.com/875/main/result.css");
/* 2. 扉页垫底水印字体：花体英文 (Dancing Script) */
@import url("https://fonts.googleapis.com/css2?family=Dancing+Script:wght@400;700&display=swap");

/* === 一、全局控制（利用变量自定义常见如文本颜色、边框颜色、自定义文案等） === */
:root {
  /* ------------------------------------ */
  /* ✏️ 【造物主控制台：自定义文案与URL专区】 ✏️ */
  /* 所有的文字、前缀、后缀、字体链接都在这里修改 */

  /* 1. 字体变量 */
  --font-main: "ChillHuoSong_F", serif; /* 主体中文字体 */
  --font-cursive: 'Dancing Script', cursive; /* 花体英文字体 */

  /* ==================================== */
  /* 👑 【Char / AI 角色视角专属配置】 👑 */
  /* ==================================== */
  --avatar-img-char: url('https://i.postimg.cc/dQ4Ltz9f/IMG-20260307-153236.jpg'); /* Char 版头横幅图片 */
  --cover-title-char: "都柏林人";     /* Char 居中主标题 */
  --cover-subtitle-char: "Dubliners"; /* Char 垫底的花体英文水印 */
  --author-prefix-char: "寒◎";             /* Char 竖排名字顶部的前缀印记 */
  --footer-text-char: "「 并未在一起亦无从离弃 」"; /* Char 底部悬停隐形寄语 */

  /* ==================================== */
  /* 👤 【User / 玩家视角专属配置】 👤 */
  /* ==================================== */
  --avatar-img-user: url('https://i.postimg.cc/KjqzqMzL/IMG-20260307-153245.jpg'); /* User 版头横幅图片 */
  --cover-title-user: "大雪将至";       /* User 居中主标题 */
  --cover-subtitle-user: "Heavy Snow"; /* User 垫底的花体英文水印 */
  --author-prefix-user: "雪◎";             /* User 竖排名字顶部的前缀印记 */
  --footer-text-user: "「 谁凭爱意要富士山私有 」"; /* User 底部悬停隐形寄语 */

  /* 3. 气泡中部：现代诗数据行（时间戳已隐藏） */
  --ui-floor-prefix: "落雪第 ";      /* 楼层前缀 */
  --ui-floor-suffix: " 片";          /* 楼层后缀 */

  --ui-time-prefix: "冬寂第 ";       /* 生成时间前缀 */
  --ui-time-suffix: " 刻";           /* 生成时间后缀 */

  --ui-token-prefix: "岁寒第 ";      /* Token数前缀 */
  --ui-token-suffix: " 圈";          /* Token数后缀 */

  /* 4. 输入框与按钮文案 */
  --input-placeholder: "冬日序诗";    /* 输入框空白提示词 */
  --load-more-text: "· 没入风雪 ·";  /* 加载更多消息按钮文案 */
  /* 思维链折叠诗意文案 (使用 \A 实现 CSS 换行) */
  --reasoning-text: "他听着雪花在天地间悠悠飘落\A悠悠地\A如同他们最终的归宿那样\A飘落在每一个生者和死者身上";

  /* ------------------------------------ */
  /* 🎨 色彩美学基调（动态融合酒馆原生系统，日间冰蓝浮雕调） */
  --book-bg-hover: rgba(255, 255, 255, 0.45);  /* 日间适应：明亮的半透明白霜遮罩 */
  --book-border: rgba(0, 0, 0, 0.08); /* 分割线与边框的极淡暗线 */

  --ink-main: var(--SmartThemeBodyColor, #2C353D); /* 正文墨雪灰（足够深，保证日间阅读性） */
  --ink-sub: #78828A;        /* 辅助信息霜冷灰 */
  --ink-accent: #5C7A92;     /* 藏书印冰川蓝（清冷克制的高亮色） */

  /* 🌟 日间发光引擎核心变量（雪地反光+微凸浮雕） 🌟 */
  /* 日间不能用亮白强光，会糊。改为：微弱的暗色实体投影 + 极淡的大面积白光反衬 */
  --glow-light: 0 1px 2px rgba(0, 0, 0, 0.05), 0 0 10px rgba(255, 255, 255, 0.6);
  --glow-strong: 0 1px 3px rgba(92, 122, 146, 0.2), 0 0 15px rgba(255, 255, 255, 0.8);
}

/* 定义全局字体与底色，并挂载日间微光引擎 */
body {
  font-family: var(--font-main);
  font-weight: normal;
  color: var(--ink-main);
  letter-spacing: 0.02em;
  text-shadow: var(--glow-light); /* 赋予全局文字微弱呼吸浮雕感 */
}

/* ★ 彻底释放酒馆原生毛玻璃控制权 ★ */
/* 已全部移去 backdrop-filter: none，请通过酒馆原生滑块控制模糊度 */
.drawer-content,
#table_drawer_content,
.options-content,
#chat {
  background-image: none !important;
  border-color: var(--book-border) !important;
  box-shadow: none !important;
}


/* ==================================================== */
/* ❄️ ⬇️⬇️⬇️ 如果不想要飘雪，请删除下面这个框里的所有代码 ⬇️⬇️⬇️ ❄️ */
/* ==================================================== */

/* 清理原生壁纸，防止干扰 */
#bg_layer {
  background-image: none !important;
}

/* ⚡ 第一层：中景慢雪（粒子超载扩充，30个点位，坐标彻底打散） ⚡ */
html::after {
  content: '';
  position: fixed;
  top: -20vh;
  left: 0;
  width: 4px;
  height: 4px;
  background: rgba(255, 255, 255, 0.7);
  border-radius: 50%;
  z-index: 9998 !important;
  pointer-events: none !important;
  filter: blur(1.5px);
  /* 极度不规则的坐标分布，深浅交错，拉大纵向距离差异制造连绵感 */
  box-shadow:
    5vw 10vh 0 rgba(255,255,255,0.6),
    35vw 45vh 1px rgba(255,255,255,0.8),
    65vw -20vh 0 rgba(255,255,255,0.5),
    90vw 80vh 2px rgba(255,255,255,0.7),
    15vw 150vh 0 rgba(255,255,255,0.9),
    45vw 110vh 1px rgba(255,255,255,0.4),
    75vw 180vh 0 rgba(255,255,255,0.8),
    25vw -60vh 2px rgba(255,255,255,0.6),
    55vw 210vh 0 rgba(255,255,255,0.5),
    85vw 30vh 1px rgba(255,255,255,0.7),
    10vw 260vh 0 rgba(255,255,255,0.8),
    /* 增量风雪 */
    18vw 5vh 1px rgba(255,255,255,0.4),
    42vw 85vh 0 rgba(255,255,255,0.7),
    78vw -10vh 2px rgba(255,255,255,0.5),
    95vw 135vh 0 rgba(255,255,255,0.6),
    8vw 190vh 1px rgba(255,255,255,0.8),
    38vw 230vh 0 rgba(255,255,255,0.4),
    68vw 60vh 1px rgba(255,255,255,0.9),
    88vw 250vh 0 rgba(255,255,255,0.5),
    50vw 165vh 2px rgba(255,255,255,0.7),
    2vw 115vh 0 rgba(255,255,255,0.6),
    30vw -35vh 1px rgba(255,255,255,0.8),
    60vw 140vh 0 rgba(255,255,255,0.4),
    80vw 205vh 1px rgba(255,255,255,0.6),
    22vw 280vh 0 rgba(255,255,255,0.7),
    48vw 20vh 2px rgba(255,255,255,0.5),
    72vw 275vh 0 rgba(255,255,255,0.8),
    92vw -45vh 1px rgba(255,255,255,0.4),
    12vw 70vh 0 rgba(255,255,255,0.9),
    58vw 295vh 1px rgba(255,255,255,0.6);
  animation: loya-snow-mid 16s linear infinite; /* 增量后略微提速，体现风势 */
}

/* 中景飘雪动画：打破直线，加大微摇摆的幅度 */
@keyframes loya-snow-mid {
  0% { transform: translate3d(0, 0, 0); opacity: 0; }
  10% { opacity: 1; }
  30% { transform: translate3d(10vw, 35vh, 0); }
  60% { transform: translate3d(-2vw, 75vh, 0); opacity: 1; }
  90% { opacity: 1; }
  100% { transform: translate3d(12vw, 130vh, 0); opacity: 0; }
}

/* 🌪️ 第二层：前景纷飞雪（海量粒子超载，45个点位，构建满屏大雪） 🌪️ */
/* 核心动画与逻辑提供：User */
body::after {
  content: '';
  position: fixed;
  top: -100vh;
  left: 0;
  width: 3px;
  height: 3px;
  border-radius: 50%;
  background: rgba(255,255,255,0.05); /* 基础透明度极低，靠数量取胜 */
  filter: blur(1px);
  z-index: 9999 !important;
  pointer-events: none !important;
  /* 暴雪矩阵：大量低透明度粒子，混杂极少量稍亮粒子 */
  box-shadow:
    10vw 20vh 0 rgba(255,255,255,0.1),
    25vw 80vh 0 rgba(255,255,255,0.3),
    40vw 10vh 0 rgba(255,255,255,0.05),
    55vw 90vh 0 rgba(255,255,255,0.2),
    70vw 30vh 0 rgba(255,255,255,0.15),
    85vw 150vh 0 rgba(255,255,255,0.08),
    15vw 120vh 0 rgba(255,255,255,0.25),
    35vw 180vh 0 rgba(255,255,255,0.12),
    60vw 60vh 0 rgba(255,255,255,0.06),
    80vw 100vh 0 rgba(255,255,255,0.18),
    95vw 40vh 0 rgba(255,255,255,0.22),
    /* 增量矩阵 1 */
    5vw 55vh 0 rgba(255,255,255,0.07),
    18vw 110vh 0 rgba(255,255,255,0.14),
    32vw -20vh 0 rgba(255,255,255,0.09),
    48vw 145vh 0 rgba(255,255,255,0.28),
    65vw -10vh 0 rgba(255,255,255,0.11),
    75vw 195vh 0 rgba(255,255,255,0.04),
    90vw 85vh 0 rgba(255,255,255,0.19),
    12vw 210vh 0 rgba(255,255,255,0.16),
    28vw -40vh 0 rgba(255,255,255,0.21),
    42vw 230vh 0 rgba(255,255,255,0.05),
    /* 增量矩阵 2 (深化覆盖面) */
    52vw 45vh 0 rgba(255,255,255,0.13),
    68vw 135vh 0 rgba(255,255,255,0.24),
    88vw 225vh 0 rgba(255,255,255,0.08),
    2vw 160vh 0 rgba(255,255,255,0.17),
    22vw 25vh 0 rgba(255,255,255,0.06),
    38vw 165vh 0 rgba(255,255,255,0.15),
    58vw -55vh 0 rgba(255,255,255,0.27),
    72vw 70vh 0 rgba(255,255,255,0.1),
    82vw -30vh 0 rgba(255,255,255,0.2),
    98vw 205vh 0 rgba(255,255,255,0.12),
    /* 增量矩阵 3 (极低透明度填充缝隙) */
    8vw -70vh 0 rgba(255,255,255,0.05),
    15vw 260vh 0 rgba(255,255,255,0.03),
    30vw 100vh 0 rgba(255,255,255,0.08),
    45vw -5vh 0 rgba(255,255,255,0.04),
    50vw 280vh 0 rgba(255,255,255,0.11),
    62vw 115vh 0 rgba(255,255,255,0.06),
    70vw 250vh 0 rgba(255,255,255,0.02),
    85vw 5vh 0 rgba(255,255,255,0.07),
    92vw 170vh 0 rgba(255,255,255,0.09),
    25vw 290vh 0 rgba(255,255,255,0.05),
    78vw 285vh 0 rgba(255,255,255,0.06),
    40vw 310vh 0 rgba(255,255,255,0.04),
    88vw 300vh 0 rgba(255,255,255,0.08),
    55vw 320vh 0 rgba(255,255,255,0.05);
  /* 遵照反馈：风雪势大，将时间微调至 10s，比 12s 稍显急促，比 8s 从容 */
  animation: loya-snow-soft 10s linear infinite;
}

/* 摇摆雪花下落动画：微调 X 轴偏移，放大风吹的物理幅度 */
@keyframes loya-snow-soft {
  0% { transform: translate(0, 0); opacity: 0; }
  10% { opacity: 1; }
  25% { transform: translate(-15px, 55vh); }
  50% { transform: translate(25px, 110vh); opacity: 1; }
  75% { transform: translate(-10px, 165vh); }
  90% { opacity: 1; }
  100% { transform: translate(20px, 220vh); opacity: 0; }
}

/* ==================================================== */
/* ❄️ ⬆️⬆️⬆️ 如果不想要飘雪，请删除上面这个框里的所有代码 ⬆️⬆️⬆️ ❄️ */
/* ==================================================== */


/* ===== 二、顶栏（全版本兼容类名补丁） ===== */
#top-settings-holder {
  background-color: var(--SmartThemeBlurTintColor) !important;
  border: none !important;
  border-bottom: 1px solid var(--book-border) !important;
  box-shadow: none !important;
  border-radius: 0 !important;
  padding-top: 2px !important;
  padding-bottom: 2px !important;
}

#top-bar {
  border-radius: 0 !important;
  background-color: transparent !important;
  box-shadow: none !important;
  border: none !important;
}

/* 顶栏图标基础设置：文字与发光 */
#top-settings-holder .drawer-icon {
  opacity: 1;
  outline: none !important;
  -webkit-tap-highlight-color: transparent;
}
#top-settings-holder .drawer-icon::before {
  font-family: var(--font-main) !important;
  font-size: 1em;
  font-weight: normal;
  color: var(--ink-sub) !important;
  text-shadow: var(--glow-light);
  transition: color 0.8s ease-out, transform 0.8s ease-out, text-shadow 0.8s ease-out;
  display: inline-block;
  vertical-align: middle;
}

/* 展开状态保持高亮强光 */
#top-settings-holder .drawer-icon.openIcon::before {
  color: var(--ink-accent) !important;
  text-shadow: var(--glow-strong);
  transform: none !important;
}

/* 防卡死包裹：悬停效果 */
@media (hover: hover) {
  #top-settings-holder .drawer-icon:hover::before {
    color: var(--ink-accent) !important;
    text-shadow: var(--glow-strong);
    transform: none !important;
    transition: color 0.6s ease-out, text-shadow 0.6s ease-out;
  }
}

/* 点击（激活）时的物理反馈 */
#top-settings-holder .drawer-icon:active::before {
  content: '◎' !important;
  transform: scale(0.75) !important;
  color: var(--ink-accent) !important;
  text-shadow: var(--glow-strong);
  transition: transform 0.5s ease, color 0.5s ease !important;
}

/* 图标替换为诗意单字（思绪与雪散又写几轮冬） */
/* 类名借用自作者：@gloriamukuhiba */
.drawer-icon.fa-sliders.closedIcon::before, .drawer-icon.fa-sliders.openIcon::before { content: '思' !important; }
.drawer-icon.fa-plug.closedIcon::before, .drawer-icon.fa-plug.openIcon::before, .drawer-icon.fa-plug-circle-exclamation.closedIcon::before, .drawer-icon.fa-plug-circle-exclamation.openIcon::before { content: '绪' !important; }
.drawer-icon.fa-font.closedIcon::before, .drawer-icon.fa-font.openIcon::before { content: '与' !important; }
.drawer-icon.fa-book-atlas.closedIcon::before, .drawer-icon.fa-book-atlas.openIcon::before { content: '雪' !important; }
.drawer-icon.fa-user.closedIcon::before, .drawer-icon.fa-user.openIcon::before, .drawer-icon.fa-user-cog.closedIcon::before, .drawer-icon.fa-user-cog.openIcon::before { content: '散' !important; }
.drawer-icon.fa-image.closedIcon::before, .drawer-icon.fa-image.openIcon::before, .drawer-icon.fa-panorama.closedIcon::before, .drawer-icon.fa-panorama.openIcon::before { content: '又' !important; }
.drawer-icon.fa-cubes.closedIcon::before, .drawer-icon.fa-cubes.openIcon::before { content: '写' !important; }
.drawer-icon.fa-face-smile.closedIcon::before, .drawer-icon.fa-face-smile.openIcon::before { content: '轮' !important; }
.drawer-icon.fa-address-card.closedIcon::before, .drawer-icon.fa-address-card.openIcon::before { content: '冬' !important; }
.drawer-icon.fa-bars-progress.closedIcon::before, .drawer-icon.fa-bars-progress.openIcon::before { content: '几' !important; }


/* ===== 三、底栏（极简修整） ===== */
#send_form {
  background-color: var(--SmartThemeChatTintColor) !important;
  border: none !important;
  border-top: 1px solid var(--book-border) !important;
  border-radius: 0 !important;
  padding: 4px 10px;
  box-shadow: none !important;
  min-height: auto !important;
}

#send_textarea {
  background-color: transparent !important;
  border: none !important;
  border-bottom: 1px dashed var(--book-border) !important;
  border-radius: 0 !important;
  font-family: var(--font-main);
  color: var(--ink-main) !important;
  text-shadow: var(--glow-light);
  padding: 2px 5px 2px 15px;
  box-shadow: none !important;
  min-height: 24px !important;
  clip-path: none !important;
  transition: border-color 0.8s ease;
}
#send_textarea:focus {
  border-bottom: 1px solid var(--ink-accent) !important;
  outline: none !important;
}

/* 底栏图标：微缩与发光 */
#send_form [class*="fa-"]::before {
  color: var(--ink-sub) !important;
  font-size: 14px !important;
  text-shadow: var(--glow-light);
  transition: color 0.8s ease, text-shadow 0.8s ease;
}

@media (hover: hover) {
  #send_form [class*="fa-"]:hover::before {
    color: var(--ink-accent) !important;
    text-shadow: var(--glow-strong);
  }
}


/* ===== 四、聊天区域（天地分离与全流式排序） ===== */
#chat {
  padding: 20px 10px !important;
}

/* 1. 彻底融化原生双层容器壁垒 */
.mes .mesAvatarWrapper,
.mes .mes_block {
  display: contents !important;
}

/* 2. 气泡卡片本体：化身为真正的 Flex 全局总指挥 */
.mes {
  position: relative !important;
  width: 100% !important;
  max-width: none !important;
  padding-top: 130px !important;
  padding-bottom: 55px !important;
  margin: 0 0 25px 0 !important;
  background: transparent !important;
  border: none !important;
  box-shadow: none !important;
  display: flex !important;
  flex-direction: column !important;
  align-items: center !important;
  gap: 0px;
}

/* ---------------------------------------------------- */
/* 无边框版头题图横幅 */
/* ---------------------------------------------------- */
.mes .avatar {
  display: flex !important;
  order: 0 !important;
  width: 80% !important;
  height: 40px !important;
  margin: 10px 0 40px 0 !important;
  padding: 0 !important;
  border: none !important;
  border-radius: 0 !important;
  overflow: hidden !important;
  justify-content: center !important;
  align-items: center !important;
  background-color: transparent !important;
  box-shadow: 0 0 20px rgba(255, 255, 255, 0.2) !important; /* 日间横幅微光 */
  z-index: 3;
}
.mes .avatar img {
  display: block !important;
  width: 100% !important;
  height: 80px !important;
  object-fit: cover !important;
  object-position: center center !important;
  border: none !important;
  border-radius: 0 !important;
  box-shadow: none !important;
}
/* 头像图片URL双轨分离注入 */
.mes[is_user="false"] .avatar img { content: var(--avatar-img-char) !important; }
.mes[is_user="true"] .avatar img { content: var(--avatar-img-user) !important; }


/* ---------------------------------------------------- */
/* 交互天际线（天地分离布局） */
/* ---------------------------------------------------- */
.mes_buttons {
  position: absolute !important;
  top: 0px !important;
  bottom: 0px !important;
  left: 0 !important;
  right: 0 !important;
  margin: 0 auto !important;
  pointer-events: none !important;
  writing-mode: horizontal-tb !important;
  text-orientation: mixed !important;
  display: flex !important;
  flex-direction: row !important;
  flex-wrap: nowrap !important;
  justify-content: center !important;
  align-items: flex-start !important;
  width: 100% !important;
  gap: 8px !important;
  opacity: 0.15;
  transition: opacity 0.8s ease;
  z-index: 10;
}
.mes:hover .mes_buttons {
  opacity: 1;
}

.mes_buttons .mes_button,
.mes_buttons .favorite-toggle-icon,
.mes_buttons .mes_edit_buttons {
