.mes .swipe_left { left: 2% !important; transform: none !important; }
.mes .swipe_left i, .mes .swipe_left .fa-chevron-left { font-size: 0 !important; }
.mes .swipe_left i::before, .mes .swipe_left .fa-chevron-left::before {
  content: '上篇◎' !important;
  font-family: var(--font-main) !important;
  font-size: 13px !important;
  font-style: normal !important;
  letter-spacing: 0.05em;
  color: var(--ink-sub);
  text-shadow: var(--glow-light);
  white-space: nowrap;
  transition: color 0.8s ease, text-shadow 0.8s ease;
}

.mes .swipe_right, .mes .swipeRightBlock { right: 2% !important; transform: none !important; }
.mes .swipe_right i, .mes .swipe_right .fa-chevron-right,
.mes .swipeRightBlock i, .mes .swipeRightBlock .fa-chevron-right { font-size: 0 !important; }
.mes .swipe_right i::before, .mes .swipe_right .fa-chevron-right::before,
.mes .swipeRightBlock i::before, .mes .swipeRightBlock .fa-chevron-right::before {
  content: '◎下篇' !important;
  font-family: var(--font-main) !important;
  font-size: 13px !important;
  font-style: normal !important;
  letter-spacing: 0.05em;
  color: var(--ink-sub);
  text-shadow: var(--glow-light);
  white-space: nowrap;
  transition: color 0.8s ease, text-shadow 0.8s ease;
}

.mes .swipe_info,
.mes .swipes_counter {
  position: absolute !important;
  bottom: 5px !important;
  left: 0 !important;
  right: 0 !important;
  margin: 0 auto !important;
  text-align: center !important;
  width: fit-content;
  font-family: var(--font-main) !important;
  font-size: 11px !important;
  color: var(--ink-sub) !important;
  text-shadow: var(--glow-light);
