.mes:hover .swipes_counter { opacity: 1; }

@media (hover: hover) {
  .mes .swipe_left:hover i::before, .mes .swipe_left:hover .fa-chevron-left::before,
  .mes .swipe_right:hover i::before, .mes .swipe_right:hover .fa-chevron-right::before,
