    text-shadow: var(--glow-strong) !important;
  }
}


/* ---------------------------------------------------- */
/* 2.5 封面文案双轨分离渲染 (Char / User) */
/* ---------------------------------------------------- */

/* a. 水印层 */
.mes::after {
  position: absolute !important;
  top: 25px !important;
  left: 0 !important;
  right: 0 !important;
  margin: 0 auto !important;
  text-align: center;
  font-family: var(--font-cursive);
  font-size: 5em;
  color: var(--ink-sub);
  text-shadow: var(--glow-light);
  opacity: 0.08; /* 日间模式下保持低透明度 */
  z-index: 1;
  white-space: nowrap;
  pointer-events: none;
  transition: color 0.8s ease, opacity 0.8s ease, text-shadow 0.8s ease;
}
.mes:hover::after {
  color: var(--ink-accent);
  text-shadow: var(--glow-strong);
  opacity: 0.15;
}
.mes[is_user="false"]::after { content: var(--cover-subtitle-char); }
.mes[is_user="true"]::after { content: var(--cover-subtitle-user); }

/* b. 居中主标题 */
.mes::before {
  position: absolute !important;
  top: 55px !important;
  left: 0 !important;
  right: 0 !important;
  margin: 0 auto !important;
  text-align: center;
  font-family: var(--font-main);
  font-size: 1.6em;
  letter-spacing: 0.4em;
  color: var(--ink-accent);
  text-shadow: var(--glow-strong);
  z-index: 2;
  white-space: nowrap;
  pointer-events: none;
}
.mes[is_user="false"]::before { content: var(--cover-title-char); }
.mes[is_user="true"]::before { content: var(--cover-title-user); }


/* ---------------------------------------------------- */
/* 3. 内部元素文档流严密排序（Order 魔法全开） */
/* ---------------------------------------------------- */

/* --- Order 1：名字竖排居中 --- */
.mes .ch_name {
  order: 1 !important;
  display: flex !important;
  justify-content: center !important;
  align-items: center !important;
  writing-mode: vertical-rl;
  text-orientation: upright;
  margin: 0 0 25px 0 !important;
  padding: 0 !important;
  font-family: var(--font-main);
  font-size: 0.95em !important;
  font-weight: normal;
  color: var(--ink-accent);
  text-shadow: var(--glow-strong);
  letter-spacing: 0.2em;
  z-index: 3;
}
.mes .ch_name::before {
  color: var(--ink-accent);
  font-size: 0.9em;
  margin-bottom: 12px;
  letter-spacing: 0;
}
.mes[is_user="false"] .ch_name::before { content: var(--author-prefix-char); }
.mes[is_user="true"] .ch_name::before { content: var(--author-prefix-user); }

/* --- Order 2, 3, 4：现代诗数据 --- */
.mes .mesIDDisplay i, .mes .mes_timer i, .mes .tokenCounterDisplay i { display: none !important; }
.mes .timestamp { display: none !important; }

.mes .mesIDDisplay, .mes .mes_timer, .mes .tokenCounterDisplay {
  display: block !important;
  width: 100%;
  text-align: center;
  font-family: var(--font-main);
  font-size: 0.75em !important;
  color: var(--ink-sub) !important;
  text-shadow: var(--glow-light);
  margin: 3px 0 !important;
  letter-spacing: 0.1em;
  opacity: 0.85;
  z-index: 3;
}
.mes .mesIDDisplay { order: 2 !important; }
.mes .mes_timer { order: 3 !important; }
.mes .tokenCounterDisplay {
  order: 4 !important;
  margin-bottom: 25px !important;
  border-bottom: 1px solid var(--book-border);
  padding-bottom: 25px !important;
}

.mes .mesIDDisplay::before { content: var(--ui-floor-prefix); margin-right: 4px; }
.mes .mesIDDisplay::after { content: var(--ui-floor-suffix); margin-left: 4px; }
.mes .mes_timer::before { content: var(--ui-time-prefix); margin-right: 4px; }
.mes .mes_timer::after { content: var(--ui-time-suffix); margin-left: 4px; }
.mes .tokenCounterDisplay::before { content: var(--ui-token-prefix); margin-right: 4px; }
.mes .tokenCounterDisplay::after { content: var(--ui-token-suffix); margin-left: 4px; }


/* --- Order 5：思维链区块（限定 AI，安全居中） --- */
.mes[is_user="false"] details:has(.mes_reasoning_summary),
.mes[is_user="false"] .mes_block details {
  order: 5 !important;
  width: 85% !important;
  margin: 0 auto 20px auto !important;
  z-index: 3;
  display: block !important;
}


/* --- Order 7：正文区块 (宽屏释放) --- */
/* 宽屏代码借用自作者：@inkfoxxxx */
.mes .mes_text {
  order: 7 !important;
  line-height: 1.85 !important;
  color: var(--ink-main);
  text-shadow: var(--glow-light);
  width: 100% !important;
  padding: 0px !important;
  margin: 0 !important;
  text-align: justify;
  z-index: 3;
}
.mes_text p { margin-bottom: 1.2em !important; }

.mes_text i, .mes_text em {
  font-style: normal !important;
  color: var(--ink-sub);
}

.mes_text blockquote {
  margin: 1.5em 0 !important;
  padding: 10px 15px !important;
  background-color: var(--book-bg-hover);
  border-left: 3px solid var(--ink-accent);
  color: var(--ink-main);
  font-size: 0.95em;
  border-radius: 0;
  box-shadow: inset 0 0 15px rgba(255, 255, 255, 0.3); /* 日间块内微光 */
}
.mes_text b, .mes_text strong {
  font-weight: normal;
  color: var(--ink-accent);
  text-shadow: var(--glow-strong);
  border-bottom: 1px solid var(--book-border);
}

.mes.last_mes { margin-bottom: 0px !important; }
.mes.last_mes .mesAvatarWrapper { padding-bottom: 0px !important; }


/* ===== 五、滚动条（上下滑动的）+滑动条（已隐匿） ===== */
::-webkit-scrollbar { width: 6px; height: 6px; background-color: transparent; }
::-webkit-scrollbar-track { background-color: transparent; }
::-webkit-scrollbar-thumb {
  background-color: var(--book-border);
  border-radius: 10px;
  border: none;
  box-shadow: 0 0 5px rgba(255, 255, 255, 0.5) !important;
}
::-webkit-scrollbar-thumb:hover { background-color: var(--ink-sub); }

/* 遵照指令：彻底隐匿原生滑动控制条，保持界面纯净 */
input[type="range"] {
  display: none !important;
}
/* 此处保留伪元素逻辑结构，以符合零容忍保真协议，但由于 display:none 不会在视觉上生效 */
input[type="range"]::-webkit-slider-runnable-track {
  width: 100%;
  height: 2px;
  background: var(--book-border);
  border-radius: 0px;
  border: none;
}
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  margin-top: -6px;
  height: 14px;
  width: 6px;
  background-color: var(--ink-main);
  border: none;
  border-radius: 0;
  box-shadow: 0 0 8px rgba(255, 255, 255, 0.8);
  transition: transform 0.8s ease;
}
input[type="range"]:hover::-webkit-slider-thumb,
input[type="range"]:active::-webkit-slider-thumb {
  transform: scale(1.2);
  background-color: var(--ink-accent);
}
input[type="range"]::-moz-range-track {
  height: 2px;
  background: var(--book-border);
  border-radius: 0px;
  border: none;
}
input[type="range"]::-moz-range-thumb {
  height: 14px;
  width: 6px;
  background-color: var(--ink-main);
  border: none;
  border-radius: 0;
  box-shadow: 0 0 8px rgba(255, 255, 255, 0.8);
}


/* ===== 六、输入框提示文字自定义 ===== */
#nonQRFormItems { position: relative; }
#send_textarea::placeholder { color: transparent !important; text-shadow: none !important; }
#nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
  content: var(--input-placeholder);
  color: var(--ink-sub);
  text-shadow: var(--glow-light);
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  font-family: var(--font-main);
  font-size: 0.75em;
  pointer-events: none;
  z-index: 10;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: calc(100% - 30px);
}


/* ===== 七、正则+脚本易读+防误触 ===== */
#saved_regex_scripts,
#saved_scoped_scripts,
#saved_preset_scripts,
#global-script-list,
#character-script-list {
  margin-right: 80px !important;
}

.regex-script-label.flex-container,
.flex-container .script-item {
  flex-wrap: wrap !important;
  padding: 5px 10px;
  border-radius: 4px;
  margin-bottom: 5px;
  background: var(--book-bg-hover);
  border: 1px solid var(--book-border);
}

.regex-script-label.flex-container .regex_script_name,
.script-item .script-item-name {
  flex-basis: 100%;
  white-space: normal;
  overflow: visible;
  text-overflow: clip;
  word-break: break-word;
  font-weight: normal;
  font-size: 1.05em;
  color: var(--ink-main);
  text-shadow: var(--glow-light);
}

.regex-script-label.flex-container > .flex-container.flexnowrap,
.script-item .script-item-control {
  width: 100%;
  justify-content: flex-start;
}


/* ===== 八、“加载更多消息”美化（图书翻页感） ===== */
#show_more_messages {
  font-size: 0 !important;
  color: transparent !important;
  display: block;
  padding: 8px 30px;
  margin: 30px auto;
  width: fit-content;
  background-color: transparent;
  border: 1px solid var(--book-border);
  border-radius: 50px;
  box-shadow: none;
  cursor: pointer;
  transition: all 0.8s ease;
}
#show_more_messages::before {
  content: var(--load-more-text);
  font-family: var(--font-main);
  font-size: 13px !important;
  color: var(--ink-sub) !important;
  letter-spacing: 0.2em;
  text-shadow: var(--glow-light);
  transition: color 0.8s ease, text-shadow 0.8s ease;
}
@media (hover: hover) {
  #show_more_messages:hover {
    background-color: var(--book-bg-hover);
    border-color: var(--ink-accent);
    box-shadow: 0 0 15px rgba(255, 255, 255, 0.5);
  }
  #show_more_messages:hover::before {
    color: var(--ink-accent) !important;
    text-shadow: var(--glow-strong);
  }
}


/* ===== 九、思维链美化（高度截断、隐式滚动与空壳防御） ===== */
@keyframes poetic-breathing {
  0% { opacity: 0.3; filter: blur(1px); text-shadow: var(--glow-light); }
  50% { opacity: 1; filter: blur(0px); text-shadow: var(--glow-strong); }
  100% { opacity: 0.3; filter: blur(1px); text-shadow: var(--glow-light); }
}

.mes[is_user="false"] details:has(.mes_reasoning:empty) { display: none !important; }
.mes[is_user="false"] .mes_reasoning_header_title:empty::before { content: none !important; display: none !important; }

.mes[is_user="false"] .mes_reasoning_summary {
  list-style: none;
  cursor: pointer;
  display: flex !important;
  justify-content: center !important;
  align-items: center;
  width: 100%;
  margin: 0 !important;
}
.mes[is_user="false"] .mes_reasoning_summary::-webkit-details-marker { display: none !important; }

.mes[is_user="false"] .mes_reasoning_header {
  background: transparent !important;
  border: none !important;
  border-radius: 0;
  padding: 5px 0;
  transition: all 0.8s ease-in-out;
  text-align: center;
}
.mes[is_user="false"] .mes_reasoning_summary:hover .mes_reasoning_header {
  transform: none;
  box-shadow: none;
}

.mes[is_user="false"] .mes_reasoning_header_title {
  font-size: 0 !important;
  display: inline-block;
}
.mes[is_user="false"] .mes_reasoning_header_title::before {
  content: var(--reasoning-text);
  font-family: var(--font-main);
  font-size: 0.85rem !important;
  color: var(--ink-accent);
  font-weight: normal;
  letter-spacing: 0.1em;
  white-space: pre-wrap;
  line-height: 1.8;
  display: inline-block;
  animation: poetic-breathing 8s ease-in-out infinite;
}

.mes[is_user="false"] .mes_reasoning_arrow { display: none !important; }

.mes[is_user="false"] .mes_reasoning {
  margin: 10px auto 25px auto !important;
  padding: 15px 25px !important;
  background-color: var(--book-bg-hover) !important;
  border: 1px solid var(--book-border) !important;
  border-left: 3px double var(--book-border) !important;
  border-radius: 2px 6px 6px 2px !important;
  color: var(--ink-sub) !important;
