.mes[is_user="false"] .mes_reasoning::-webkit-scrollbar { width: 4px !important; }
.mes[is_user="false"] .mes_reasoning::-webkit-scrollbar-track { background: transparent !important; }
.mes[is_user="false"] .mes_reasoning::-webkit-scrollbar-thumb {
