  border-radius: 10px !important;
}
.mes[is_user="false"] .mes_reasoning::-webkit-scrollbar-thumb:hover { background: var(--ink-accent) !important; }


/* ===== 十、收藏栏左右滑动查看角色 ===== */
.hotswap.avatars_inline {
  display: flex;
  flex-wrap: nowrap;
  overflow-x: auto;
  padding-right: 15px;
}
.hotswap.avatars_inline::-webkit-scrollbar { display: none; }
.hotswap.avatars_inline { scrollbar-width: none; }
@media (max-width: 768px) {
  .hotswap.avatars_inline { overflow: auto; flex-wrap: wrap; }
}


/* ===== 十一、附加模块：隐形寄语双轨分离 ===== */
/* 创作者：AI 建构师 Loya */
.mes_text::after {
  display: block;
  width: 100%;
  margin: 30px auto 0 auto;
  text-align: center;
  color: var(--ink-sub);
  font-family: var(--font-main);
  font-size: 12px;
  letter-spacing: 0.4em;
  text-shadow: var(--glow-light);
  opacity: 0.05;
  filter: blur(2px);
  transition: opacity 1.5s ease, filter 1.5s ease, text-shadow 1.5s ease;
}

.mes:hover .mes_text::after {
  opacity: 0.8;
  filter: blur(0px);
  text-shadow: var(--glow-strong);
}

/* 隐形寄语内容双轨分离注入 */
.mes[is_user="false"] .mes_text::after { content: var(--footer-text-char); }
.mes[is_user="true"] .mes_text::after { content: var(--footer-text-user); }


/* ===== 十二、补丁模块：解决提示词头部标题看不见的问题 ===== */
/* 代码出处 / 借用自作者：blue */
