  width: 100% !important;
  display: flex !important;
  justify-content: center !important;
  align-items: center !important;
}

/* 2. 强行将标题标签转化为全宽块级元素 */
.mes[is_user="false"] .mes_reasoning_header_title {
  display: block !important;
  width: 100% !important;
  text-align: center !important;
}

/* 3. 最终对内部伪元素文本施加绝对居中，并锁定多行渲染 */
.mes[is_user="false"] .mes_reasoning_header_title::before {
  display: block !important;
  width: 100% !important;
  text-align: center !important;
  white-space: pre-wrap !important;
}
/* ===== 翻页按钮·自带清场终极补丁 ===== */

/* 0. 先把所有旧伪元素内容强制归零，清除历史残留 */
.mes[is_user="false"] .swipe_left::before,
.mes[is_user="false"] .swipe_left::after,
.mes[is_user="false"] .swipe_right::before,
.mes[is_user="false"] .swipe_right::after {
