.mes[is_user="false"] .swipe_left i,
.mes[is_user="false"] .swipe_right i {
  font-size: 0 !important;
  color: transparent !important;
}

/* 2. 左翻页注入文字 */
.mes[is_user="false"] .swipe_left::before {
  content: '上篇◎' !important;
  font-family: var(--font-main) !important;
  font-size: 13px !important;
  color: var(--ink-sub) !important;
  letter-spacing: 0.05em;
  transition: color 0.8s ease;
  white-space: nowrap;
}

/* 3. 右翻页注入文字 */
.mes[is_user="false"] .swipe_right::before {
  content: '◎下篇' !important;
  font-family: var(--font-main) !important;
  font-size: 13px !important;
  color: var(--ink-sub) !important;
  letter-spacing: 0.05em;
  transition: color 0.8s ease;
  white-space: nowrap;
}

/* 4. 悬停点亮 */
.mes[is_user="false"] .swipe_left:hover::before,
.mes[is_user="false"] .swipe_right:hover::before {
  color: var(--ink-accent) !important;
}
